-- ============================================================
-- TABELA: DM_VENDAS.TEMPLATES_MENSAGENS
-- ============================================================

CREATE TABLE "TEMPLATES_MENSAGENS" (
    "ID"                   NUMBER GENERATED BY DEFAULT AS IDENTITY
                               MINVALUE 1
                               MAXVALUE 9999999999999999999999999999
                               INCREMENT BY 1
                               START WITH 1
                               CACHE 20
                               NOORDER NOCYCLE NOKEEP NOSCALE
                               NOT NULL ENABLE,
    "NOME_TEMPLATE"        VARCHAR2(150 CHAR)  NOT NULL ENABLE,
    "TIPO"                 VARCHAR2(40 CHAR)   NOT NULL ENABLE,
    "CLASSIFICACAO_RFV"    VARCHAR2(60 CHAR),
    "MENSAGEM"             CLOB                NOT NULL ENABLE,
    "ESCOPO"               VARCHAR2(30 CHAR)   NOT NULL ENABLE,
    "VENDEDOR_ID"          NUMBER,
    "EMPRESA_ID"           NUMBER,
    "DATA_CRIACAO"         DATE DEFAULT SYSDATE NOT NULL ENABLE,
    "DATA_ATUALIZACAO"     DATE DEFAULT SYSDATE NOT NULL ENABLE,
    "USUARIO_CRIACAO"      VARCHAR2(100 CHAR),
    "USUARIO_ATUALIZACAO"  VARCHAR2(100 CHAR),

    CONSTRAINT "CK_TM_TIPO"
        CHECK (TIPO IN ('PADRAO', 'PERSONALIZADO', 'AUTOMACAO')) ENABLE,

    CONSTRAINT "CK_TM_ESCOPO"
        CHECK (ESCOPO IN ('SISTEMA', 'EMPRESA', 'USUARIO')) ENABLE,

    CONSTRAINT "PK_TEMPLATES_MENSAGENS"
        PRIMARY KEY ("ID")
        USING INDEX
            PCTFREE 10 INITRANS 2 MAXTRANS 255 COMPUTE STATISTICS
            STORAGE (INITIAL 65536 NEXT 1048576 MINEXTENTS 1
                     MAXEXTENTS 2147483645 PCTINCREASE 0
                     FREELISTS 1 FREELIST GROUPS 1
                     BUFFER_POOL DEFAULT FLASH_CACHE DEFAULT
                     CELL_FLASH_CACHE DEFAULT)
            TABLESPACE "DADOS"
        ENABLE
)
SEGMENT CREATION IMMEDIATE
PCTFREE 10 PCTUSED 40 INITRANS 1 MAXTRANS 255
NOCOMPRESS LOGGING
STORAGE (INITIAL 65536 NEXT 1048576 MINEXTENTS 1
         MAXEXTENTS 2147483645 PCTINCREASE 0
         FREELISTS 1 FREELIST GROUPS 1
         BUFFER_POOL DEFAULT FLASH_CACHE DEFAULT
         CELL_FLASH_CACHE DEFAULT)
TABLESPACE "DADOS"
LOB ("MENSAGEM") STORE AS SECUREFILE (
    TABLESPACE "DADOS"
    ENABLE STORAGE IN ROW
    CHUNK 8192
    NOCACHE LOGGING NOCOMPRESS KEEP_DUPLICATES
    STORAGE (INITIAL 106496 NEXT 1048576 MINEXTENTS 1
             MAXEXTENTS 2147483645 PCTINCREASE 0
             BUFFER_POOL DEFAULT FLASH_CACHE DEFAULT
             CELL_FLASH_CACHE DEFAULT)
);

